#include<bits/stdc++.h>
#define LL long long
using namespace std;
const LL mod = 2017 ;LL n,m,k,sum;
struct Mat{LL n,m,a[105][105];}ans,t;
Mat operator * (const Mat &x , const Mat &y){
    Mat z;z.n=x.n,z.m=y.m;
    for(int i=0;i<=x.n;i++)for(int j=0;j<=y.m;j++)z.a[i][j]=0;
    for(int i=0;i<=x.n;i++)for(int j=0;j<=y.m;j++)
        for(int o=0;o<=x.m;o++)z.a[i][j]=(z.a[i][j]+x.a[i][o]*y.a[o][j])%mod;
    return z;
}
void QP(){
    for(int i=0;i<=n;i++)ans.a[i][i]=1;
    while(k){if(k&1)ans=ans*t;t=t*t,k>>=1;}return;
}
int main(){
    cin>>n>>m;t.n=n,t.m=n,ans.n=n,ans.m=n;
    for(int i=1;i<=m;i++){int x,y;cin>>x>>y;t.a[x][y]=1,t.a[y][x]=1;}
    for(int i=1;i<=n;i++)t.a[i][0]=1;for(int i=0;i<=n;i++)t.a[i][i]=1;
    cin>>k;QP();for(int i=0;i<=n;i++)sum=(sum+ans.a[1][i])%mod;cout<<sum<<"\n";
    return 0;
}
